+### Transaction Support
+
+```typescript
+// Begin transaction
+agent.db.exec('BEGIN TRANSACTION');
+
+try {
+  // Perform multiple operations
+  const ep1 = agent.reflexion.store({ /* ... */ });
+  const ep2 = agent.reflexion.store({ /* ... */ });
+  const skill = agent.skills.create({ /* ... */ });
+
+  // Commit transaction
+  agent.db.exec('COMMIT');
+} catch (error) {
+  // Rollback on error
+  agent.db.exec('ROLLBACK');
+  throw error;
+}
+```
